import{_ as t,o as a,c as r,a2 as n}from"./chunks/framework.ufzXw1qY.js";const u=JSON.parse('{"title":"OpenSIN-AI Capabilities","description":"","frontmatter":{},"headers":[],"relativePath":"guide/opensin-ai-agent-features.md","filePath":"guide/opensin-ai-agent-features.md"}'),i={name:"guide/opensin-ai-agent-features.md"};function o(s,e,d,c,l,p){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="opensin-ai-capabilities" tabindex="-1">OpenSIN-AI Capabilities <a class="header-anchor" href="#opensin-ai-capabilities" aria-label="Permalink to &quot;OpenSIN-AI Capabilities&quot;">​</a></h1><p>OpenSIN-AI is a fleet-first agent system built for autonomous work, not a single chatbot. This page summarizes the current user-visible capabilities and where they live in the product surface.</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Canonical ownership and repo mapping live in <a href="https://github.com/OpenSIN-AI/OpenSIN-overview/blob/main/docs/CANONICAL-REPOS.md" target="_blank" rel="noreferrer"><code>OpenSIN-overview/docs/CANONICAL-REPOS.md</code></a>. This page explains the current product experience, not org governance.</p></div><h2 id="what-opensin-users-can-do" tabindex="-1">What OpenSIN Users Can Do <a class="header-anchor" href="#what-opensin-users-can-do" aria-label="Permalink to &quot;What OpenSIN Users Can Do&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>What it gives you</th><th>Where it lives</th></tr></thead><tbody><tr><td><strong>Autonomous fleet control</strong></td><td>Run a team of specialized agents instead of a single prompt loop</td><td><code>chat.opensin.ai</code></td></tr><tr><td><strong>Public documentation</strong></td><td>Learn the current system without reading raw source code</td><td><code>docs.opensin.ai</code></td></tr><tr><td><strong>Marketing surface</strong></td><td>Understand the product and the value proposition</td><td><code>opensin.ai</code></td></tr><tr><td><strong>Marketplace / paid layer</strong></td><td>Browse plans, bundles, and premium access paths</td><td><code>my.opensin.ai</code></td></tr><tr><td><strong>Agent orchestration</strong></td><td>Dispatch work across teams and worker agents</td><td><code>OpenSIN-backend</code></td></tr><tr><td><strong>A2A communication</strong></td><td>Let agents coordinate directly instead of bottlenecking through one process</td><td>OpenSIN core stack</td></tr></tbody></table><h2 id="current-strengths" tabindex="-1">Current Strengths <a class="header-anchor" href="#current-strengths" aria-label="Permalink to &quot;Current Strengths&quot;">​</a></h2><h3 id="_1-fleet-first-design" tabindex="-1">1. Fleet-First Design <a class="header-anchor" href="#_1-fleet-first-design" aria-label="Permalink to &quot;1. Fleet-First Design&quot;">​</a></h3><p>OpenSIN is built around teams and workers, not one monolithic assistant. That means work can be specialized, parallelized, and audited.</p><h3 id="_2-multiple-surfaces-for-different-audiences" tabindex="-1">2. Multiple Surfaces for Different Audiences <a class="header-anchor" href="#_2-multiple-surfaces-for-different-audiences" aria-label="Permalink to &quot;2. Multiple Surfaces for Different Audiences&quot;">​</a></h3><ul><li>users start at the docs and marketing surfaces</li><li>authenticated operators use <code>chat.opensin.ai</code></li><li>contributors use the documentation and canonical repo map</li><li>maintainers use the org SSOT and infrastructure repos</li></ul><h3 id="_3-strong-canonical-ownership" tabindex="-1">3. Strong Canonical Ownership <a class="header-anchor" href="#_3-strong-canonical-ownership" aria-label="Permalink to &quot;3. Strong Canonical Ownership&quot;">​</a></h3><p>The platform is now structured around a small number of canonical repos. This reduces drift and makes it easier to know where a change belongs.</p><h2 id="surface-map" tabindex="-1">Surface Map <a class="header-anchor" href="#surface-map" aria-label="Permalink to &quot;Surface Map&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Domain</th><th>Purpose</th><th>Audience</th></tr></thead><tbody><tr><td><code>opensin.ai</code></td><td>Marketing / product story</td><td>New users, developers</td></tr><tr><td><code>my.opensin.ai</code></td><td>Marketplace / paid layer</td><td>Buyers, subscribers</td></tr><tr><td><code>chat.opensin.ai</code></td><td>Authenticated dashboard</td><td>Operators, power users</td></tr><tr><td><code>docs.opensin.ai</code></td><td>Canonical docs</td><td>Everyone</td></tr><tr><td><code>blog.opensin.ai</code></td><td>Updates and launches</td><td>Community</td></tr></tbody></table><h2 id="roadmap-direction" tabindex="-1">Roadmap Direction <a class="header-anchor" href="#roadmap-direction" aria-label="Permalink to &quot;Roadmap Direction&quot;">​</a></h2><p>OpenSIN is moving toward:</p><ul><li>clearer user journeys across surfaces</li><li>less duplicate repo ownership</li><li>more consistent docs and navigation</li><li>better separation between public docs and private infra notes</li><li>stronger canonical links to the owning repo of each feature</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/guide/opensin-ai-overview.html">OpenSIN-AI Overview</a></li><li><a href="/governance/domain-registry.html">Domain Registry</a></li><li><a href="/guide/a2a-protocol.html">A2A Protocol</a></li><li><a href="/guide/opensin-code.html">OpenSIN-Code</a></li></ul>',19)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
